async function main(){
  for(const c of categories) await prisma.categorie.upsert({where:{slug:c.slug},update:c,create:c})
  const cats=Object.fromEntries((await prisma.categorie.findMany()).map(c=>[c.slug,c.id]))
  for(const a of acteurs){const{categorieSlug,horaires,...data}=a;const p={...data,categorieId:cats[categorieSlug]};const ac=await prisma.acteur.upsert({where:{slug:a.slug},update:p,create:p});await prisma.horaire.deleteMany({where:{acteurId:ac.id}});if(horaires.length)await prisma.horaire.createMany({data:horaires.map((h:any)=>({...h,acteurId:ac.id}))})}
  for(const e of evenements) await prisma.evenement.upsert({where:{slug:e.slug},update:e,create:e})
  for(const ac of actus) await prisma.actu.upsert({where:{slug:ac.slug},update:ac,create:ac})
  for(const r of randos){const{pointsInteret,...data}=r;const rd=await prisma.rando.upsert({where:{slug:r.slug},update:data,create:data});await prisma.pointInteret.deleteMany({where:{randoId:rd.id}});if(pointsInteret.length)await prisma.pointInteret.createMany({data:pointsInteret.map((p:any)=>({...p,randoId:rd.id}))})}
  await prisma.numeroUtile.deleteMany({});if(numerosUtiles.length)await prisma.numeroUtile.createMany({data:numerosUtiles})
  await prisma.collecteDechets.deleteMany({});if(collectes.length)await prisma.collecteDechets.createMany({data:collectes})
  console.log('Seed OK')
}
main().catch(e=>{console.error(e);process.exit(1)}).finally(()=>prisma.$disconnect())
